import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for p in data['projects']:
        proj = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(proj, pkg['id'])] = pkg['resolvedVersion']
    return result

base = extract(b)
after = extract(a)
if base == after:
    print('All packages resolve to identical versions.')
else:
    for k in sorted(set(list(base.keys()) + list(after.keys()))):
        bv = base.get(k, 'MISSING')
        av = after.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k[0]} {k[1]}: {bv} -> {av}')
"

